INSERT INTO tours (short_title, full_title, full_description, age, price, start_date, end_date, instructor_name, difficulty, is_active) VALUES
('Камчатка', 'Незабываемое путешествие по просторам Камчатки', 'Приглашаем тебя с нами в захватывающее путешествие на край земли - в удивительную Камчатку, землю, расположенную на самом краю России. Мы будем гулять по ледниковым фьордам и альпийским лугам, по влажным тропическим лесам и засушливым степям и пустыням, увидим огромные ледники и искрящиеся бирюзовые озера - пейзажи на этом знаменитом маршруте меняются каждый день с бешеной скоростью. Нас ждут маршруты в удивительных природных заповедниках: Торрес-Дель Пайне в Чили и Лос Гласьярес в Аргентине. Вы увидите экзотический Буэнос Айрес, знаменитый ледник Перито Морено, уютную горную деревушку Эль Чалтен и многое, многое другое. А кроме того, это еще и гастрономический тур. Практически каждый вечер, там, где будет такая возможность, мы будем посещать местные локальные заведения, где можно попробовать лучшие в мире аргентинские стейки, свежую рыбу из патагонских озер, отличное вино и многое другое.', 'от 10 до 99', 80000.00, '2025-09-12', '2025-09-21', 'Екатерина', 'легкий', 1),
INSERT INTO tour_program (tour_id, day_number, short_title, full_description, sort_order) VALUES
(1, 1, 'Прилёт и заселение', 'Прилёт на Камчатку, организационная встреча участников, доезд до места проживания и отдых от длительного перелёта. Камчатка - это место, которым хочется насладиться, поэтому, если у вас получится приехать раньше, побалуйте себя и прогуляйтесь по набережной этого прекрасного города.', 1),
(1, 2, 'Знакомство с Камчаткой', 'Экскурсия по Петропавловску-Камчатскому, посещение музеев и вулканологической станции. Начало активной программы.', 2),
(1, 3, 'Восхождение на вулкан', 'Подъём на активный вулкан с профессиональными гидами. Безопасные маршруты с потрясающими видами.', 3),
(1, 4, 'Поход к горячим источникам', 'Маршрут к термальным источникам в долине Гейзеров. Релакс и природные SPA-процедуры.', 4),
(1, 5, 'Рыбалка и отдых', 'Рыбалка на реке с инструкторами, приготовление ухи на костре. Вечерние посиделки.', 5),
(1, 6, 'Возвращение', 'Организованный трансфер в аэропорт, прощальные фотографии и отъезд домой.', 6);
INSERT INTO tour_program (tour_id, day_number, short_title, full_description, sort_order) VALUES
(2, 1, 'Прибытие и размещение', 'Встреча в аэропорту, трансфер в горный отель. Знакомство с группой и инструктаж.', 1),
(2, 2, 'Снежные развлечения', 'Катание на санках, снегоходах, снежные игры и фотосессии.', 2),
(2, 3, 'Новогодняя ночь', 'Празднование Нового года с фейерверками, банкетом и подарками.', 3),
(2, 4, 'Горные прогулки', 'Лёгкие пешие прогулки по заснеженным тропам с гидом.', 4),
(2, 5, 'Отдых и SPA', 'Релакс в отеле, сауна, массаж и подготовка к отъезду.', 5);
